mapper.select:
select aa.repair_code repairCode, bb.asset_code assetCode, bb.asset_name assetName, bb.asset_typename assetTypename, bb.manufacturer, bb.spe_model speModel, aa.repair_date repairDate, aa.finish_date finishDate, aa.repair_type repairType, aa.repair_reason repairReason, aa.repair_fee repairFee, aa.repair_status repairStatus from repair aa join asset bb on aa.asset_id=bb.id where 1=1
AND bb.asset_code LIKE concat('%', #{assetCode},'%')
AND bb.asset_name LIKE concat('%', #{assetName},'%')
AND bb.asset_typeid =#{assetTypeid}
AND aa.repair_status =#{repairStatus}
AND aa.repair_type =#{repairType}
AND aa.repair_date >=#{repairStart} and aa.repair_date <= #{repairEnd}
